var e=[{id:`L4_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`엄마?`,JPN:`お母さん？`,ENG:`Mom?`,TWN:`媽媽？`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`내가…… 엄마를 죽였어……?`,JPN:`私が……お母さんを殺した……？`,ENG:`I... killed my mom...?`,TWN:`我……殺了媽媽……？`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`거짓말…… 거짓말……!`,JPN:`嘘……ウソ……！`,ENG:`No... That's a lie...!`,TWN:`騙人……騙人……！`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`……거짓이 아니다. 레아 슈나이더.`,JPN:`……噓ではない。レア・シュナイダー。`,ENG:`...It is the truth, Leah Schneider.`,TWN:`……沒有騙人，蕾亞·修奈德。`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`네가 열차에서 내리더라도 막을 수 없는 현실이다.`,JPN:`そなたが列車から降りるとしても、阻止できない現実だ。`,ENG:`That fact will not change even if you get off this train.`,TWN:`即使你離開列車，也無法改變這個事實。`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`아니야…….`,JPN:`いや……`,ENG:`No...`,TWN:`不……`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`아니야아아아아아!!`,JPN:`いやああああああ！！`,ENG:`IT CAN'T BE!!`,TWN:`不！！！`},stage:{bg:`WALL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`이런 걸 바란 적 없었어. 엄마가 미운 적도 있었지만…`,JPN:`こんなことは望んでない。お母さんが憎いって思った時もあったけど……`,ENG:`I never wanted this. I was angry at her from time to time...`,TWN:`這不是我想要的。我雖然有時候會討厭媽媽…`},stage:{bg:`WALL`,slots:{L:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L16_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`감당하기 힘들다고 생각한 적도 많았지만…`,JPN:`手に負えないって思った時も多かったけど……`,ENG:`And countless times, I thought about how it was too much for me to handle...`,TWN:`也經常感到自己無法再承受她……`},stage:{bg:`WALL`,slots:{L:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`이렇게 되는 건, 이런 식으로는 바라지 않았단 말이야…….`,JPN:`こうなるのは、こんな風には望んでなかった……`,ENG:`But not like this. I never wanted it to be like this...`,TWN:`但我從來沒有想過，會是這樣的結局……`},stage:{bg:`WALL`,slots:{L:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`WALL`,slots:{L:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NAME`,text:{KOREA:`…………아.`,JPN:`…………あ。`,ENG:`...Ah.`,TWN:`……啊。`},stage:{bg:`HARMONY2_04`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NAME`,text:{KOREA:`죽여 버렸네요.`,JPN:`殺してしまいましたね。`,ENG:`I killed her.`,TWN:`死掉了。`},stage:{bg:`HARMONY2_04`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NAME`,text:{KOREA:`……정말로.`,JPN:`……本当に。`,ENG:`...I really.`,TWN:`真的……。`},stage:{bg:`HARMONY2_04`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NAME`,text:{KOREA:`정말로, 죽여 버렸어요.`,JPN:`本当に、殺してしまいました。`,ENG:`I really... killed her.`,TWN:`真的，死掉了。`},stage:{bg:`HARMONY2_04`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`……아주머니?`,JPN:`……おばさん？`,ENG:`...Madam Schneider?`,TWN:`伯母……？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`아주머니!! 정신 차려요, 네?! 장난치지 말고 어서요!`,JPN:`おばさん！！　しっかりしてください、ね！？　冗談はやめて、早く！`,ENG:`Madam Schneider!! Wake up! This isn't the place nor time for games!`,TWN:`伯母！！你快醒醒？！你別嚇我！快醒醒！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};